{
  "files": [
    { "path": "README.md", "content": "# Minimal Node.js Project

This project includes the basic structure and endpoints required for a simple CRUD application with projects, members, tasks, and comments.
" },
    { "path": "package.json", "content": "```json
"dependencies": {
  "express": "^4.17.1"
},
"devDependencies": {
  "supertest": "^6.0.2"
}
```" },
    { "path": "src/app.js", "content": "```js
const express = require('express');
const app = express();
const port = process.env.PORT || 11434;

app.use(express.json());

// Health check endpoint
app.get('/health', (req, res) => {
  res.send({ ok: true });
});

// Projects endpoints
require('./src/modules/projects');

// Members endpoints
require('./src/modules/members');

// Tasks endpoints
require('./src/modules/tasks');

// Comments endpoints
require('./src/modules/comments');

app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});
```" },
    { "path": "src/server.js", "content": "```js
const app = require('./src/app');

module.exports = app;
```" }
  ],
  "notes": "Ensure all modules are correctly imported and exported, and that routes are properly mounted in src/app.js."
}
